# ---- checker.py tests ----


class TestChecker(unittest.TestCase):
    def test_valid_readable_directory(self) -> None:
        with tempfile.TemporaryDirectory() as d:
            result = is_valid_directory(d)
            self.assertTrue(result.success)
            self.assertEqual(result.reason, "")

    def test_valid_writable_directory(self) -> None:
        with tempfile.TemporaryDirectory() as d:
            result = is_valid_directory(d, must_be_writable=True)
            self.assertTrue(result.success)

    def test_empty_path(self) -> None:
        result = is_valid_directory("")
        self.assertFalse(result.success)
        self.assertIn("non-empty string", result.reason)

    def test_nonexistent_path(self) -> None:
        result = is_valid_directory("/nonexistent_path_xyz_12345")
        self.assertFalse(result.success)
        self.assertIn("does not exist", result.reason)

    def test_file_not_directory(self) -> None:
        with tempfile.NamedTemporaryFile() as f:
            result = is_valid_directory(f.name)
            self.assertFalse(result.success)
            self.assertIn("not a directory", result.reason)

    def test_operation_outcome_dataclass(self) -> None:
        outcome = OperationOutcome(success=True, reason="ok")
        self.assertTrue(outcome.success)
        self.assertEqual(outcome.reason, "ok")


