class TestGetIterations(unittest.TestCase):
    def test_no_iteration_column(self) -> None:
        df = pd.DataFrame({"a": [1, 2, 3]})
        with self.assertRaises(TypeError):
            get_iterations(df)

    def test_non_integer_iteration_column(self) -> None:
        df = pd.DataFrame({"iteration": ["a", "b"]})
        with self.assertRaises(TypeError):
            get_iterations(df)

    def test_valid_iterations(self) -> None:
        df = pd.DataFrame({"iteration": [1, 2, 3, 1, 2]})
        result = get_iterations(df)
        self.assertEqual(result, [1, 2, 3])

    def test_iterations_with_minus_one(self) -> None:
        df = pd.DataFrame({"iteration": [-1, 1, 2]})
        result = get_iterations(df)
        self.assertEqual(result, [1, 2])


class TestFindOpOccurrence(unittest.TestCase):
    def test_empty_df(self) -> None:
        found, series = find_op_occurrence(pd.DataFrame(), "op", 0)
        self.assertFalse(found)

    def test_missing_columns(self) -> None:
        df = pd.DataFrame({"a": [1]})
        found, series = find_op_occurrence(df, "op", 0)
        self.assertFalse(found)

    def test_find_first_occurrence(self) -> None:
        df = pd.DataFrame(
            {"s_name": ["op_a", "op_b", "op_a"], "ts": [10, 20, 30], "index": [0, 1, 2]}
        )
        found, series = find_op_occurrence(df, "op_a", 0)
        self.assertTrue(found)
        self.assertEqual(series["ts"], 10)

    def test_find_last_occurrence(self) -> None:
        df = pd.DataFrame(
            {"s_name": ["op_a", "op_b", "op_a"], "ts": [10, 20, 30], "index": [0, 1, 2]}
        )
        found, series = find_op_occurrence(df, "op_a", -1)
        self.assertTrue(found)
        self.assertEqual(series["ts"], 30)

    def test_no_match(self) -> None:
        df = pd.DataFrame({"s_name": ["op_a"], "ts": [10], "index": [0]})
        found, series = find_op_occurrence(df, "op_z", 0)
        self.assertFalse(found)

    def test_out_of_range_position(self) -> None:
        df = pd.DataFrame({"s_name": ["op_a"], "ts": [10], "index": [0]})
        found, series = find_op_occurrence(df, "op_a", 5)
        self.assertFalse(found)


class TestFindEventsByNamePatterns(unittest.TestCase):
    def test_using_decoded_names(self) -> None:
        df = pd.DataFrame(
            {"s_name": ["aten::mm", "nccl::send", "aten::add"], "index": [0, 1, 2]}
        )
        indices = find_events_by_name_patterns_using_decoded_names(df, ["aten::.*"])
        self.assertEqual(sorted(indices.tolist()), [0, 2])

    def test_using_symbol_table(self) -> None:
        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["aten::mm", "nccl::send", "aten::add"])
        sym_id_map = sym_table.get_sym_id_map()
        df = pd.DataFrame(
            {
                "name": [
                    sym_id_map["aten::mm"],
                    sym_id_map["nccl::send"],
                    sym_id_map["aten::add"],
                ],
                "index": [0, 1, 2],
            }
        )
        indices = find_events_by_name_patterns_using_symbol_table(
            df, ["aten::.*"], sym_table
        )
        self.assertEqual(sorted(indices.tolist()), [0, 2])


