class TestInferDeviceType(unittest.TestCase):
    def test_gpu_stream_only(self) -> None:
        df = pd.DataFrame({"stream": [1, 2, 3]})
        self.assertEqual(infer_device_type(df), DeviceType.GPU)

    def test_cpu_stream_only(self) -> None:
        df = pd.DataFrame({"stream": [-1, -1]})
        self.assertEqual(infer_device_type(df), DeviceType.CPU)

    def test_gpu_with_pid_tid(self) -> None:
        df = pd.DataFrame({"stream": [1, 2], "pid": [0, 0], "tid": [0, 0]})
        self.assertEqual(infer_device_type(df), DeviceType.GPU)

    def test_cpu_with_pid_tid(self) -> None:
        df = pd.DataFrame({"stream": [-1, -1], "pid": [123, 123], "tid": [456, 456]})
        self.assertEqual(infer_device_type(df), DeviceType.CPU)

    def test_unknown_mixed(self) -> None:
        df = pd.DataFrame({"stream": [-1, 1], "pid": [123, 123], "tid": [456, 456]})
        self.assertEqual(infer_device_type(df), DeviceType.UNKNOWN)


class TestGroupingPattern(unittest.TestCase):
    def test_match(self) -> None:
        gp = GroupingPattern(pattern=re.compile(r"aten::.*"))
        self.assertTrue(gp.match("aten::mm"))
        self.assertFalse(gp.match("nccl::send"))

    def test_inverse_match(self) -> None:
        gp = GroupingPattern(pattern=re.compile(r"aten::.*"), inverse_match=True)
        self.assertFalse(gp.match("aten::mm"))
        self.assertTrue(gp.match("nccl::send"))

    def test_hash(self) -> None:
        gp1 = GroupingPattern(pattern=re.compile(r"aten::.*"))
        gp2 = GroupingPattern(pattern=re.compile(r"aten::.*"))
        self.assertEqual(hash(gp1), hash(gp2))


class TestToGroupingPattern(unittest.TestCase):
    def test_from_string(self) -> None:
        gp = to_grouping_pattern("aten::.*", group_name="test")
        self.assertEqual(gp.group_name, "test")
        self.assertTrue(gp.match("aten::mm"))

    def test_from_list(self) -> None:
        gp = to_grouping_pattern(["aten::.*", "nccl::.*"])
        self.assertTrue(gp.match("aten::mm"))
        self.assertTrue(gp.match("nccl::send"))

    def test_from_compiled_regex(self) -> None:
        gp = to_grouping_pattern(re.compile(r"aten::.*"))
        self.assertTrue(gp.match("aten::mm"))

    def test_from_grouping_pattern(self) -> None:
        orig = GroupingPattern(pattern=re.compile(r"test"))
        result = to_grouping_pattern(orig)
        self.assertIs(result, orig)

    def test_invalid_type(self) -> None:
        with self.assertRaises(ValueError):
            to_grouping_pattern(123)  # type: ignore[arg-type]


