class TestTimeRangeFilter(unittest.TestCase):
    def test_filter_in_range(self) -> None:
        df = pd.DataFrame({"ts": [10, 20, 30], "dur": [5, 5, 5]})
        f = TimeRangeFilter((10, 35))
        result = f(df)
        self.assertEqual(len(result), 3)

    def test_filter_excludes_out_of_range(self) -> None:
        df = pd.DataFrame({"ts": [10, 20, 30], "dur": [5, 5, 10]})
        f = TimeRangeFilter((10, 35))
        result = f(df)
        self.assertEqual(len(result), 2)  # last event ends at 40 > 35

    def test_no_ts_column(self) -> None:
        df = pd.DataFrame({"a": [1]})
        f = TimeRangeFilter((0, 100))
        result = f(df)
        self.assertEqual(len(result), 1)

    def test_invalid_range(self) -> None:
        with self.assertRaises(ValueError):
            TimeRangeFilter((100, 10))

    def test_invalid_type(self) -> None:
        with self.assertRaises(ValueError):
            TimeRangeFilter("bad")  # type: ignore[arg-type]


