class TestCompositeFilter(unittest.TestCase):
    def test_chain_filters(self) -> None:
        df = pd.DataFrame({"iteration": [1, 2, 3], "rank": [0, 0, 1]})
        f = CompositeFilter([IterationFilter([1, 2]), RankFilter(0)])
        result = f(df)
        self.assertEqual(len(result), 2)

    def test_invalid_filter(self) -> None:
        with self.assertRaises(TypeError):
            CompositeFilter(["not a filter"])  # type: ignore[list-item]

    def test_self_reference(self) -> None:
        # CompositeFilter checks if any filter is self
        f = CompositeFilter.__new__(CompositeFilter)
        with self.assertRaises(ValueError):
            CompositeFilter.__init__(f, [f])


class TestMemCopyEventFilter(unittest.TestCase):
    def test_empty_df(self) -> None:
        f = MemCopyEventFilter("Memcpy HtoD")
        result = f(pd.DataFrame())
        self.assertTrue(result.empty)

    def test_with_symbol_table(self) -> None:
        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["Memcpy HtoD", "gpu_memcpy", "aten::mm", "kernel"])
        sym_id_map = sym_table.get_sym_id_map()
        df = pd.DataFrame(
            {
                "name": [sym_id_map["Memcpy HtoD"], sym_id_map["aten::mm"]],
                "cat": [sym_id_map["gpu_memcpy"], sym_id_map["kernel"]],
            }
        )
        f = MemCopyEventFilter("Memcpy HtoD")
        result = f(df, sym_table)
        self.assertEqual(len(result), 1)

    def test_unknown_memory_copy_type(self) -> None:
        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["aten::mm"])
        df = pd.DataFrame({"name": [0], "cat": [0]})
        f = MemCopyEventFilter("nonexistent_type")
        result = f(df, sym_table)
        self.assertTrue(result.empty)

    def test_with_constructor_symbol_table(self) -> None:
        """When symbol_table is passed via constructor, it is used."""
        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["Memcpy HtoD", "gpu_memcpy"])
        sym_id_map = sym_table.get_sym_id_map()
        df = pd.DataFrame(
            {
                "name": [sym_id_map["Memcpy HtoD"]],
                "cat": [sym_id_map["gpu_memcpy"]],
            }
        )
        f = MemCopyEventFilter("Memcpy HtoD", symbol_table=sym_table)
        result = f(df)  # no symbol_table at call site
        self.assertEqual(len(result), 1)


