class TestUtilsFunctions(unittest.TestCase):
    def test_normalize_path_dot_prefix(self) -> None:
        from hta.utils.utils import normalize_path

        result = normalize_path("./subdir")
        self.assertTrue(result.endswith("subdir"))
        self.assertFalse(result.startswith("./"))

    def test_normalize_path_dot_only(self) -> None:
        from hta.utils.utils import normalize_path

        result = normalize_path("./")
        self.assertTrue(len(result) > 2)

    def test_normalize_path_tilde_prefix(self) -> None:
        from hta.utils.utils import normalize_path

        result = normalize_path("~/subdir")
        self.assertFalse(result.startswith("~/"))

    def test_normalize_path_tilde_only(self) -> None:
        from hta.utils.utils import normalize_path

        result = normalize_path("~/")
        self.assertTrue(len(result) > 2)

    def test_normalize_path_absolute(self) -> None:
        from hta.utils.utils import normalize_path

        result = normalize_path("/tmp/test")
        self.assertEqual(result, "/tmp/test")

    def test_is_computer_kernel_deprecated(self) -> None:
        from hta.utils.utils import is_computer_kernel

        # is_computer_kernel is deprecated alias for is_compute_kernel
        self.assertTrue(is_computer_kernel("custom_gemm_kernel"))

    def test_get_memory_kernel_type(self) -> None:
        from hta.utils.utils import get_memory_kernel_type

        self.assertEqual(get_memory_kernel_type("Memcpy DtoH (Device)"), "Memcpy DtoH")
        self.assertEqual(get_memory_kernel_type("Memcpy HtoD (Pinned)"), "Memcpy HtoD")
        self.assertEqual(get_memory_kernel_type("Memset (Device)"), "Memset")
        self.assertEqual(get_memory_kernel_type("custom_dma_op"), "Memcpy Unknown")

    def test_normalize_gpu_stream_numbers(self) -> None:
        from hta.utils.utils import normalize_gpu_stream_numbers

        df = pd.DataFrame({"stream": [1, "2", None, "abc"]})
        normalize_gpu_stream_numbers(df)
        self.assertEqual(df["stream"].tolist(), [1, 2, -1, -1])

    def test_normalize_gpu_stream_numbers_no_column(self) -> None:
        from hta.utils.utils import normalize_gpu_stream_numbers

        df = pd.DataFrame({"a": [1]})
        normalize_gpu_stream_numbers(df)  # should not raise

    def test_get_symbol_column_names(self) -> None:
        from hta.utils.utils import get_symbol_column_names

        df = pd.DataFrame({"s_name": ["a"], "s_cat": ["b"]})
        name_col, cat_col = get_symbol_column_names(df)
        self.assertEqual(name_col, "s_name")
        self.assertEqual(cat_col, "s_cat")

    def test_get_symbol_column_names_no_symbol_cols(self) -> None:
        from hta.utils.utils import get_symbol_column_names

        df = pd.DataFrame({"name": [1], "cat": [2]})
        name_col, cat_col = get_symbol_column_names(df)
        # Falls back to empty or name/cat
        self.assertIn(name_col, ["", "name"])

    def test_get_kernel_type_other(self) -> None:
        from hta.utils.utils import get_kernel_type

        # A name that matches none of the kernel type patterns
        result = get_kernel_type("cudaDeviceSynchronize")
        self.assertEqual(result, "OTHER")

