class TestPrepareTimelineGPUEvents(unittest.TestCase):
    def test_prepare_with_valid_data(self) -> None:
        from hta.analyzers.timeline import prepare_timeline_gpu_events

        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["aten::mm", "kernel", "nccl::send", "cpu_op"])
        sym_id_map = sym_table.get_sym_id_map()

        df = pd.DataFrame(
            {
                "iteration": [1, 1],
                "name": [sym_id_map["aten::mm"], sym_id_map["nccl::send"]],
                "cat": [sym_id_map["kernel"], sym_id_map["cpu_op"]],
                "rank": [0, 0],
                "stream": [7, 7],
                "ts": [1000, 2000],
                "dur": [500, 100],
            }
        )

        result = prepare_timeline_gpu_events(df, sym_table)
        self.assertFalse(result.empty)
        self.assertIn("calibrated_start_global", result.columns)
        self.assertIn("calibrated_end_global", result.columns)
        self.assertIn("task", result.columns)
        self.assertIn("label", result.columns)

    def test_prepare_with_explicit_filters(self) -> None:
        from hta.analyzers.timeline import prepare_timeline_gpu_events

        sym_table = TraceSymbolTable()
        sym_table.add_symbols(["aten::mm", "kernel"])
        sym_id_map = sym_table.get_sym_id_map()

        df = pd.DataFrame(
            {
                "iteration": [1, 2],
                "name": [sym_id_map["aten::mm"], sym_id_map["aten::mm"]],
                "cat": [sym_id_map["kernel"], sym_id_map["kernel"]],
                "rank": [0, 1],
                "stream": [7, 8],
                "ts": [1000, 2000],
                "dur": [500, 100],
            }
        )

        result = prepare_timeline_gpu_events(
            df, sym_table, ranks=[0], iterations=[1], streams=[7]
        )
        self.assertEqual(len(result), 1)

    @patch("hta.analyzers.timeline.px.timeline")
    def test_plot_timeline_with_ranks(self, mock_px_timeline: Mock) -> None:
        from hta.analyzers.timeline import plot_timeline

        mock_fig = Mock()
        mock_px_timeline.return_value = mock_fig

        df = pd.DataFrame(
            {
                "calibrated_start_global": pd.to_datetime([1000, 2000], unit="us"),
                "calibrated_end_global": pd.to_datetime([1500, 2500], unit="us"),
                "task": ["rank 0 stream 7", "rank 0 stream 7"],
                "label": ["op_a", "op_b"],
                "rank": [0, 0],
            }
        )
        plot_timeline("test", df, ranks=[0])
        mock_px_timeline.assert_called_once()

    @patch("hta.analyzers.timeline.px.timeline")
    def test_plot_timeline_no_rank_column(self, mock_px_timeline: Mock) -> None:
        from hta.analyzers.timeline import plot_timeline

        mock_fig = Mock()
        mock_px_timeline.return_value = mock_fig

        df = pd.DataFrame(
            {
                "calibrated_start_global": pd.to_datetime([1000], unit="us"),
                "calibrated_end_global": pd.to_datetime([1500], unit="us"),
                "task": ["task1"],
                "label": ["op_a"],
            }
        )
        plot_timeline("test", df)
        mock_px_timeline.assert_called_once()


