class TestTraceFileAdditional(unittest.TestCase):
    def test_create_rank_to_trace_dict_from_list(self) -> None:
        from hta.common.trace_file import create_rank_to_trace_dict

        data_dir = get_test_data_dir()
        trace_file = os.path.join(
            data_dir, "trace_file_list", "inference_rank_1.json.gz"
        )
        ok, result = create_rank_to_trace_dict([trace_file])
        self.assertTrue(ok)

    def test_read_write_json(self) -> None:
        """Test read_trace/write_trace with plain .json files (not .gz)."""
        from hta.common.trace_file import read_trace, write_trace

        test_data = {"traceEvents": [{"name": "test", "ph": "X"}]}
        with tempfile.TemporaryDirectory() as d:
            json_path = os.path.join(d, "test.json")
            write_trace(test_data, json_path)
            result = read_trace(json_path)
            self.assertEqual(result, test_data)

    def test_read_trace_invalid_extension(self) -> None:
        from hta.common.trace_file import read_trace

        with self.assertRaises(ValueError):
            read_trace("/tmp/test.txt")

    def test_write_trace_creates_directory(self) -> None:
        from hta.common.trace_file import write_trace

        with tempfile.TemporaryDirectory() as d:
            nested_path = os.path.join(d, "subdir", "test.json")
            write_trace({"data": 1}, nested_path)
            self.assertTrue(os.path.exists(nested_path))

    def test_update_trace_rank_no_distributed_info(self) -> None:
        """Test update_trace_rank when distributedInfo key doesn't exist."""
        from hta.common.trace_file import read_trace, update_trace_rank, write_trace

        test_data: dict[str, list[str]] = {"traceEvents": []}
        with tempfile.TemporaryDirectory() as d:
            path = os.path.join(d, "test.json.gz")
            write_trace(test_data, path)
            update_trace_rank(path, 42)
            result = read_trace(path)
            self.assertEqual(result["distributedInfo"]["rank"], 42)


class TestCheckerNotWritable(unittest.TestCase):
    def test_not_writable_directory(self) -> None:
        """Test is_valid_directory with must_be_writable on a read-only dir."""
        with tempfile.TemporaryDirectory() as d:
            read_only = os.path.join(d, "readonly")
            os.makedirs(read_only)
            os.chmod(read_only, 0o444)
            try:
                result = is_valid_directory(read_only, must_be_writable=True)
                self.assertFalse(result.success)
                self.assertIn("not writable", result.reason)
            finally:
                os.chmod(read_only, 0o755)


