class TestTraceWriteAndConvert(unittest.TestCase):
    # AI-assisted test
    def test_write_raw_trace(self) -> None:
        """Lines 665-667: write_raw_trace gzip output."""
        from hta.common.trace import Trace

        vt_dir = _vt_trace_dir()
        t = Trace(trace_dir=vt_dir)
        contents = {"traceEvents": [{"name": "test"}]}
        with tempfile.TemporaryDirectory() as d:
            out_path = os.path.join(d, "output.json.gz")
            t.write_raw_trace(out_path, contents)
            self.assertTrue(os.path.exists(out_path))
            with gzip.open(out_path, "rt") as fp:
                loaded = json.load(fp)
            self.assertEqual(loaded, contents)

