        """Lines 904-909: missing required columns returns empty list."""
        from hta.common.trace import Trace

        vt_dir = _vt_trace_dir()
        t = Trace(trace_dir=vt_dir)
        series = pd.DataFrame({"foo": [1, 2]})
        result = t.convert_time_series_to_events(series, "counter", "value")
        self.assertEqual(result, [])

