class TestCallStackGraphMethods(unittest.TestCase):
    # AI-assisted test
    def _make_simple_graph(self):
        """Helper: create a simple CallStackGraph from CPU events."""
        from hta.common.trace_call_stack import CallStackGraph, CallStackIdentity

        identity = CallStackIdentity(rank=0, pid=100, tid=200)
        df = pd.DataFrame(
            {
                "index": [0, 1, 2],
                "stream": [-1, -1, -1],
                "ts": [100, 110, 200],
                "dur": [150, 20, 50],
                "index_correlation": [-1, -1, -1],
                "correlation": [-1, -1, -1],
            }
        )
        full_df = df.copy()
        full_df["end"] = full_df["ts"] + full_df["dur"]
        full_df["parent"] = pd.array([pd.NA, pd.NA, pd.NA], dtype=pd.Int64Dtype())
        full_df["depth"] = pd.array([pd.NA, pd.NA, pd.NA], dtype=pd.Int16Dtype())
        full_df["height"] = pd.array([pd.NA, pd.NA, pd.NA], dtype=pd.Int16Dtype())
        full_df["num_kernels"] = pd.array([0, 0, 0], dtype=pd.Int32Dtype())
        full_df["kernel_dur_sum"] = pd.array([0, 0, 0], dtype=pd.Int64Dtype())
        full_df["kernel_span"] = pd.array([0, 0, 0], dtype=pd.Int64Dtype())
        full_df["first_kernel_start"] = pd.array([0, 0, 0], dtype=pd.Int64Dtype())
        full_df["last_kernel_end"] = pd.array([0, 0, 0], dtype=pd.Int64Dtype())

        correlation = pd.DataFrame(
            {"cpu_index": pd.Series(dtype=int), "gpu_index": pd.Series(dtype=int)}
        )
        sym_table = TraceSymbolTable()

        csg = CallStackGraph(
            df,
            identity,
            correlation,
            full_df,
            sym_table,
            use_existing_stack_columns=False,
            save_call_stack_to_df=True,
        )
        return csg

    def test_get_parent_nonexistent(self) -> None:
        """Lines 506-508: get_parent for nonexistent node."""
        csg = self._make_simple_graph()
        result = csg.get_parent(99999)
        self.assertEqual(result, -2)  # NON_EXISTENT_NODE_INDEX

    def test_get_children_nonexistent(self) -> None:
        """Lines 519-521: get_children for nonexistent node."""
        csg = self._make_simple_graph()
        result = csg.get_children(99999)
        self.assertEqual(result, [])

    def test_get_root(self) -> None:
        """Lines 532-538: get_root traverses to root."""
        csg = self._make_simple_graph()
        root = csg.get_root(0)
        self.assertTrue(root < 0)  # Root should be a negative index

    def test_get_root_nonexistent(self) -> None:
        """Line 532-533: get_root for nonexistent node returns NULL_NODE_INDEX."""
        csg = self._make_simple_graph()
        result = csg.get_root(99999)
        self.assertEqual(result, -1)  # NULL_NODE_INDEX

    def test_get_path_to_root(self) -> None:
        """Lines 549-560: get_path_to_root."""
        csg = self._make_simple_graph()
        # Node 1 is child of node 0
        path = csg.get_path_to_root(1)
        self.assertIn(1, path)
        self.assertTrue(len(path) >= 2)

    def test_get_path_to_root_nonexistent(self) -> None:
        """Line 549-550: nonexistent node returns empty list."""
        csg = self._make_simple_graph()
        path = csg.get_path_to_root(99999)
        self.assertEqual(path, [])

    def test_get_paths_to_leaves(self) -> None:
        """Lines 575-594: get_paths_to_leaves."""
        csg = self._make_simple_graph()
        root_idx = csg.root_index
        paths = csg.get_paths_to_leaves(root_idx)
        self.assertTrue(len(paths) >= 1)

    def test_get_leaf_nodes(self) -> None:
        """Lines 596-606: get_leaf_nodes."""
        csg = self._make_simple_graph()
        leaves = csg.get_leaf_nodes(csg.root_index)
        self.assertTrue(len(leaves) >= 1)

    def test_get_descendants(self) -> None:
        """Lines 608-621: get_descendants."""
        csg = self._make_simple_graph()
        desc = csg.get_descendants(csg.root_index)
        self.assertTrue(len(desc) >= 1)

    def test_get_dataframe(self) -> None:
        """Line 624: get_dataframe returns df."""
        csg = self._make_simple_graph()
        df = csg.get_dataframe()
        self.assertFalse(df.empty)

    def test_repr(self) -> None:
        """Lines 271-278: __repr__."""
        csg = self._make_simple_graph()
        s = repr(csg)
        self.assertIn("CallStackGraph", s)

    def test_get_depth(self) -> None:
        """Lines 750-758: get_depth."""
        csg = self._make_simple_graph()
        depth = csg.get_depth()
        self.assertFalse(depth.empty)

    def test_dfs_traverse(self) -> None:
        """Lines 870-887: dfs_traverse with callbacks."""
        csg = self._make_simple_graph()
        entered = []
        exited = []

        def enter_fn(nid, node):
            entered.append(nid)

        def exit_fn(nid, node):
            exited.append(nid)

        csg.dfs_traverse(enter_fn, exit_fn)
        self.assertTrue(len(entered) > 0)
        self.assertEqual(len(entered), len(exited))


class TestCallStackGraphHasValidStackColumns(unittest.TestCase):
    # AI-assisted test
    def test_missing_stack_columns(self) -> None:
        """Lines 289-291: missing parent/depth/height columns → False."""
        from hta.common.trace_call_stack import CallStackGraph

        df = pd.DataFrame({"index": [0], "stream": [-1], "ts": [100], "dur": [50]})
        full_df = df.copy()
        full_df["end"] = full_df["ts"] + full_df["dur"]
        # No parent/depth/height columns — _has_valid_stack_columns returns False
        csg = CallStackGraph.__new__(CallStackGraph)
        csg.full_df = full_df
        csg.df = df
        result = csg._has_valid_stack_columns()
        self.assertFalse(result)

    def test_all_parent_minus_one(self) -> None:
        """Lines 300-302: parent all -1 → False."""
        from hta.common.trace_call_stack import CallStackGraph

        csg = CallStackGraph.__new__(CallStackGraph)
        full_df = pd.DataFrame(
            {
                "index": [0, 1],
                "stream": [-1, -1],
                "ts": [100, 200],
                "dur": [50, 50],
                "parent": [-1, -1],
                "depth": [0, 0],
                "height": [0, 0],
            }
        )
        csg.full_df = full_df
        csg.df = full_df
        result = csg._has_valid_stack_columns()
        self.assertFalse(result)


